// ============================================================================
func (q *Queries) ListDashboardTemplates(ctx context.Context) ([]DashboardTemplate, error) {
	rows, err := q.db.Query(ctx, listDashboardTemplates)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	items := []DashboardTemplate{}
	for rows.Next() {
		var i DashboardTemplate
		if err := rows.Scan(
			&i.ID,
			&i.Name,
			&i.Description,
			&i.PreviewImageUrl,
			&i.Layout,
			&i.IsDefault,
			&i.SortOrder,
			&i.TargetRoles,
			&i.CreatedAt,
			&i.UpdatedAt,
		); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

