const setDefaultDashboard = `-- name: SetDefaultDashboard :exec
UPDATE user_dashboards
SET is_default = TRUE
WHERE id = $1 AND user_id = $2
`

type SetDefaultDashboardParams struct {
	ID     pgtype.UUID `json:"id"`
	UserID string      `json:"user_id"`
}

func (q *Queries) SetDefaultDashboard(ctx context.Context, arg SetDefaultDashboardParams) error {
	_, err := q.db.Exec(ctx, setDefaultDashboard, arg.ID, arg.UserID)
	return err
}

const updateDashboard = `-- name: UpdateDashboard :one
UPDATE user_dashboards
SET
    name = COALESCE($3, name),
    description = COALESCE($4, description),
    layout = COALESCE($5, layout),
    visibility = COALESCE($6, visibility)
WHERE id = $1 AND user_id = $2
RETURNING id, user_id, workspace_id, name, description, is_default, layout, visibility, share_token, is_enforced, enforced_for_roles, created_via, created_at, updated_at
`

type UpdateDashboardParams struct {
	ID          pgtype.UUID `json:"id"`
	UserID      string      `json:"user_id"`
	Name        *string     `json:"name"`
	Description *string     `json:"description"`
	Layout      []byte      `json:"layout"`
	Visibility  *string     `json:"visibility"`
}

func (q *Queries) UpdateDashboard(ctx context.Context, arg UpdateDashboardParams) (UserDashboard, error) {
	row := q.db.QueryRow(ctx, updateDashboard,
		arg.ID,
		arg.UserID,
		arg.Name,
		arg.Description,
		arg.Layout,
		arg.Visibility,
	)
	var i UserDashboard
	err := row.Scan(
		&i.ID,
		&i.UserID,
		&i.WorkspaceID,
		&i.Name,
		&i.Description,
		&i.IsDefault,
		&i.Layout,
		&i.Visibility,
		&i.ShareToken,
		&i.IsEnforced,
		&i.EnforcedForRoles,
		&i.CreatedVia,
		&i.CreatedAt,
		&i.UpdatedAt,
	)
	return i, err
}

